import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.BWuWLRhz.js";const c=JSON.parse(`{"title":"Build a Sovereign app","description":"Create a plugin that uses Sovereign's shared platform foundations for a custom workflow.","frontmatter":{"title":"Build a Sovereign app","description":"Create a plugin that uses Sovereign's shared platform foundations for a custom workflow."},"headers":[],"relativePath":"get-started/developers.md","filePath":"get-started/developers.md"}`),r={name:"get-started/developers.md"};function n(l,e,s,d,p,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="build-an-app-on-sovereign" tabindex="-1">Build an app on Sovereign <a class="header-anchor" href="#build-an-app-on-sovereign" aria-label="Permalink to &quot;Build an app on Sovereign&quot;">​</a></h1><p>In the user interface it is an <strong>app</strong>. In the architecture and source code it is delivered as a <strong>plugin</strong> with a manifest and SDK boundary.</p><h2 id="start-with-the-workflow" tabindex="-1">Start with the workflow <a class="header-anchor" href="#start-with-the-workflow" aria-label="Permalink to &quot;Start with the workflow&quot;">​</a></h2><p>Define the user problem before choosing platform capabilities. A focused plugin should own its domain while using shared runtime services through supported contracts.</p><h2 id="reuse-platform-foundations" tabindex="-1">Reuse platform foundations <a class="header-anchor" href="#reuse-platform-foundations" aria-label="Permalink to &quot;Reuse platform foundations&quot;">​</a></h2><p>Available contracts include authentication context, app-scoped database access, the workspace shell, and the shared design system. Other capabilities have their own maturity and compatibility requirements; check the relevant documentation instead of importing runtime internals.</p><h2 id="follow-the-plugin-path" tabindex="-1">Follow the plugin path <a class="header-anchor" href="#follow-the-plugin-path" aria-label="Permalink to &quot;Follow the plugin path&quot;">​</a></h2><ol><li>Read the <a href="/plugin-development.html">plugin development guide</a>.</li><li>Define the plugin manifest and routes.</li><li>Use <code>@sovereignfs/sdk</code> for runtime capabilities.</li><li>Use <code>@sovereignfs/ui</code> for reusable interface components and tokens.</li><li>Keep user-scoped data tenant-aware and plugin tables slug-prefixed.</li><li>Test the plugin boundary, database behavior, UI, and access rules.</li><li>Validate compatibility before distribution or installation.</li></ol><h2 id="architectural-rule" tabindex="-1">Architectural rule <a class="header-anchor" href="#architectural-rule" aria-label="Permalink to &quot;Architectural rule&quot;">​</a></h2><p>Plugins must not import from runtime internals. The SDK is the supported boundary, and capabilities that are not exposed there are not available to a plugin merely because their host implementation exists.</p><p><a href="/docs/developers.html">Open the full developer documentation</a></p>',11)])])}const f=t(r,[["render",n]]);export{c as __pageData,f as default};
